#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MOD 1000000009
#define MAX_N 100000

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int heights[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &heights[i]);
        }
        long long unique_climbs = 0;
        for (int i = 0; i < N; i++) {
            for (int j = i + 1; j < N; j++) {
                int diff[j - i];
                for (int k = i; k < j; k++) {
                    diff[k - i] = heights[k + 1] - heights[k];
                }
                int hash = 0;
                for (int k = 0; k < j - i; k++) {
                    hash = (hash * 100 + diff[k]) % MOD;
                }
                int found = 0;
                for (int k = 0; k < i; k++) {
                    for (int l = k + 1; l < i; l++) {
                        int diff2[l - k];
                        for (int m = k; m < l; m++) {
                            diff2[m - k] = heights[m + 1] - heights[m];
                        }
                        int hash2 = 0;
                        for (int m = 0; m < l - k; m++) {
                            hash2 = (hash2 * 100 + diff2[m]) % MOD;
                        }
                        if (hash == hash2) {
                            found = 1;
                            break;
                        }
                    }
                    if (found) break;
                }
                if (!found) unique_climbs++;
            }
        }
        printf("%lld\n", unique_climbs % MOD);
    }
    return 0;
}

