import java.util.HashMap;
import java.util.Map;
import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int N = scanner.nextInt();
            int[] heights = new int[N];
            for (int i = 0; i < N; i++) {
                heights[i] = scanner.nextInt();
            }
            long unique_climbs = 0;
            Map<Integer, Boolean> climbs = new HashMap<>();
            for (int i = 0; i < N; i++) {
                for (int j = i + 1; j < N; j++) {
                    int[] diff = new int[j - i];
                    for (int k = i; k < j; k++) {
                        diff[k - i] = heights[k + 1] - heights[k];
                    }
                    int hash = 0;
                    for (int k = 0; k < j - i; k++) {
                        hash = (hash * 100 + diff[k]) % 1000000009;
                    }
                    if (!climbs.containsKey(hash)) {
                        climbs.put(hash, true);
                        unique_climbs++;
                    }
                }
            }
            System.out.println(unique_climbs % 1000000009);
        }
    }
}

